/// These values define the type of firmware release.  These values indicate the first version or release of this type.  For example the first alpha release would be 64, the second would be 65.
/// FIRMWARE_VERSION_TYPE
#[repr(i32)]
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum FirmwareVersionType {
  /// development release
  /// FIRMWARE_VERSION_TYPE_DEV
  FIRMWARE_VERSION_TYPE_DEV = 0,
  /// alpha release
  /// FIRMWARE_VERSION_TYPE_ALPHA
  FIRMWARE_VERSION_TYPE_ALPHA = 64,
  /// beta release
  /// FIRMWARE_VERSION_TYPE_BETA
  FIRMWARE_VERSION_TYPE_BETA = 128,
  /// release candidate
  /// FIRMWARE_VERSION_TYPE_RC
  FIRMWARE_VERSION_TYPE_RC = 192,
  /// official stable release
  /// FIRMWARE_VERSION_TYPE_OFFICIAL
  FIRMWARE_VERSION_TYPE_OFFICIAL = 255
}

impl FirmwareVersionType {
  pub fn from_value(value: i32) -> Self {
    match value {
      0 => Self::FIRMWARE_VERSION_TYPE_DEV,
      64 => Self::FIRMWARE_VERSION_TYPE_ALPHA,
      128 => Self::FIRMWARE_VERSION_TYPE_BETA,
      192 => Self::FIRMWARE_VERSION_TYPE_RC,
      255 => Self::FIRMWARE_VERSION_TYPE_OFFICIAL,
      _ => Self::FIRMWARE_VERSION_TYPE_DEV,
    }
  }
}

/// Flags to report failure cases over the high latency telemtry.
/// HL_FAILURE_FLAG
#[repr(i32)]
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum HlFailureFlag {
  /// GPS failure.
  /// HL_FAILURE_FLAG_GPS
  HL_FAILURE_FLAG_GPS = 1,
  /// Differential pressure sensor failure.
  /// HL_FAILURE_FLAG_DIFFERENTIAL_PRESSURE
  HL_FAILURE_FLAG_DIFFERENTIAL_PRESSURE = 2,
  /// Absolute pressure sensor failure.
  /// HL_FAILURE_FLAG_ABSOLUTE_PRESSURE
  HL_FAILURE_FLAG_ABSOLUTE_PRESSURE = 4,
  /// Accelerometer sensor failure.
  /// HL_FAILURE_FLAG_3D_ACCEL
  HL_FAILURE_FLAG_3D_ACCEL = 8,
  /// Gyroscope sensor failure.
  /// HL_FAILURE_FLAG_3D_GYRO
  HL_FAILURE_FLAG_3D_GYRO = 16,
  /// Magnetometer sensor failure.
  /// HL_FAILURE_FLAG_3D_MAG
  HL_FAILURE_FLAG_3D_MAG = 32,
  /// Terrain subsystem failure.
  /// HL_FAILURE_FLAG_TERRAIN
  HL_FAILURE_FLAG_TERRAIN = 64,
  /// Battery failure/critical low battery.
  /// HL_FAILURE_FLAG_BATTERY
  HL_FAILURE_FLAG_BATTERY = 128,
  /// RC receiver failure/no rc connection.
  /// HL_FAILURE_FLAG_RC_RECEIVER
  HL_FAILURE_FLAG_RC_RECEIVER = 256,
  /// Offboard link failure.
  /// HL_FAILURE_FLAG_OFFBOARD_LINK
  HL_FAILURE_FLAG_OFFBOARD_LINK = 512,
  /// Engine failure.
  /// HL_FAILURE_FLAG_ENGINE
  HL_FAILURE_FLAG_ENGINE = 1024,
  /// Geofence violation.
  /// HL_FAILURE_FLAG_GEOFENCE
  HL_FAILURE_FLAG_GEOFENCE = 2048,
  /// Estimator failure, for example measurement rejection or large variances.
  /// HL_FAILURE_FLAG_ESTIMATOR
  HL_FAILURE_FLAG_ESTIMATOR = 4096,
  /// Mission failure.
  /// HL_FAILURE_FLAG_MISSION
  HL_FAILURE_FLAG_MISSION = 8192
}

impl HlFailureFlag {
  pub fn from_value(value: i32) -> Self {
    let variants = [
      Self::HL_FAILURE_FLAG_GPS,
      Self::HL_FAILURE_FLAG_DIFFERENTIAL_PRESSURE,
      Self::HL_FAILURE_FLAG_ABSOLUTE_PRESSURE,
      Self::HL_FAILURE_FLAG_3D_ACCEL,
      Self::HL_FAILURE_FLAG_3D_GYRO,
      Self::HL_FAILURE_FLAG_3D_MAG,
      Self::HL_FAILURE_FLAG_TERRAIN,
      Self::HL_FAILURE_FLAG_BATTERY,
      Self::HL_FAILURE_FLAG_RC_RECEIVER,
      Self::HL_FAILURE_FLAG_OFFBOARD_LINK,
      Self::HL_FAILURE_FLAG_ENGINE,
      Self::HL_FAILURE_FLAG_GEOFENCE,
      Self::HL_FAILURE_FLAG_ESTIMATOR,
      Self::HL_FAILURE_FLAG_MISSION,
    ];
    for variant in variants {
      if (variant as i32) == value {
        return variant;
      }
    }
    let mut sorted: Vec<Self> = variants.into_iter().filter(|v| *v as i32 > 0).collect();
    sorted.sort_by(|a, b| (*b as i32).cmp(&(*a as i32)));
    for variant in sorted {
      if (value & (variant as i32)) != 0 {
        return variant;
      }
    }
    return Self::HL_FAILURE_FLAG_GPS;
  }
}

/// Actions that may be specified in MAV_CMD_OVERRIDE_GOTO to override mission execution.
/// MAV_GOTO
#[repr(i32)]
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum MavGoto {
  /// Hold at the current position.
  /// MAV_GOTO_DO_HOLD
  MAV_GOTO_DO_HOLD = 0,
  /// Continue with the next item in mission execution.
  /// MAV_GOTO_DO_CONTINUE
  MAV_GOTO_DO_CONTINUE = 1,
  /// Hold at the current position of the system
  /// MAV_GOTO_HOLD_AT_CURRENT_POSITION
  MAV_GOTO_HOLD_AT_CURRENT_POSITION = 2,
  /// Hold at the position specified in the parameters of the DO_HOLD action
  /// MAV_GOTO_HOLD_AT_SPECIFIED_POSITION
  MAV_GOTO_HOLD_AT_SPECIFIED_POSITION = 3
}

impl MavGoto {
  pub fn from_value(value: i32) -> Self {
    match value {
      0 => Self::MAV_GOTO_DO_HOLD,
      1 => Self::MAV_GOTO_DO_CONTINUE,
      2 => Self::MAV_GOTO_HOLD_AT_CURRENT_POSITION,
      3 => Self::MAV_GOTO_HOLD_AT_SPECIFIED_POSITION,
      _ => Self::MAV_GOTO_DO_HOLD,
    }
  }
}

/// These defines are predefined OR-combined mode flags. There is no need to use values from this enum, but it
/// simplifies the use of the mode flags. Note that manual input is enabled in all modes as a safety override.
/// MAV_MODE
#[repr(i32)]
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum MavMode {
  /// System is not ready to fly, booting, calibrating, etc. No flag is set.
  /// MAV_MODE_PREFLIGHT
  MAV_MODE_PREFLIGHT = 0,
  /// System is allowed to be active, under assisted RC control.
  /// MAV_MODE_STABILIZE_DISARMED
  MAV_MODE_STABILIZE_DISARMED = 80,
  /// System is allowed to be active, under assisted RC control.
  /// MAV_MODE_STABILIZE_ARMED
  MAV_MODE_STABILIZE_ARMED = 208,
  /// System is allowed to be active, under manual (RC) control, no stabilization
  /// MAV_MODE_MANUAL_DISARMED
  MAV_MODE_MANUAL_DISARMED = 64,
  /// System is allowed to be active, under manual (RC) control, no stabilization
  /// MAV_MODE_MANUAL_ARMED
  MAV_MODE_MANUAL_ARMED = 192,
  /// System is allowed to be active, under autonomous control, manual setpoint
  /// MAV_MODE_GUIDED_DISARMED
  MAV_MODE_GUIDED_DISARMED = 88,
  /// System is allowed to be active, under autonomous control, manual setpoint
  /// MAV_MODE_GUIDED_ARMED
  MAV_MODE_GUIDED_ARMED = 216,
  /// System is allowed to be active, under autonomous control and navigation (the trajectory is decided onboard and not pre-programmed by waypoints)
  /// MAV_MODE_AUTO_DISARMED
  MAV_MODE_AUTO_DISARMED = 92,
  /// System is allowed to be active, under autonomous control and navigation (the trajectory is decided onboard and not pre-programmed by waypoints)
  /// MAV_MODE_AUTO_ARMED
  MAV_MODE_AUTO_ARMED = 220,
  /// UNDEFINED mode. This solely depends on the autopilot - use with caution, intended for developers only.
  /// MAV_MODE_TEST_DISARMED
  MAV_MODE_TEST_DISARMED = 66,
  /// UNDEFINED mode. This solely depends on the autopilot - use with caution, intended for developers only.
  /// MAV_MODE_TEST_ARMED
  MAV_MODE_TEST_ARMED = 194
}

impl MavMode {
  pub fn from_value(value: i32) -> Self {
    match value {
      0 => Self::MAV_MODE_PREFLIGHT,
      80 => Self::MAV_MODE_STABILIZE_DISARMED,
      208 => Self::MAV_MODE_STABILIZE_ARMED,
      64 => Self::MAV_MODE_MANUAL_DISARMED,
      192 => Self::MAV_MODE_MANUAL_ARMED,
      88 => Self::MAV_MODE_GUIDED_DISARMED,
      216 => Self::MAV_MODE_GUIDED_ARMED,
      92 => Self::MAV_MODE_AUTO_DISARMED,
      220 => Self::MAV_MODE_AUTO_ARMED,
      66 => Self::MAV_MODE_TEST_DISARMED,
      194 => Self::MAV_MODE_TEST_ARMED,
      _ => Self::MAV_MODE_PREFLIGHT,
    }
  }
}

