/// A data stream is not a fixed set of messages, but rather a
/// recommendation to the autopilot software. Individual autopilots may or may not obey
/// the recommended messages.
/// MAV_DATA_STREAM
#[repr(i32)]
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum MavDataStream {
  /// Enable all data streams
  /// MAV_DATA_STREAM_ALL
  MAV_DATA_STREAM_ALL = 0,
  /// Enable IMU_RAW, GPS_RAW, GPS_STATUS packets.
  /// MAV_DATA_STREAM_RAW_SENSORS
  MAV_DATA_STREAM_RAW_SENSORS = 1,
  /// Enable GPS_STATUS, CONTROL_STATUS, AUX_STATUS
  /// MAV_DATA_STREAM_EXTENDED_STATUS
  MAV_DATA_STREAM_EXTENDED_STATUS = 2,
  /// Enable RC_CHANNELS_SCALED, RC_CHANNELS_RAW, SERVO_OUTPUT_RAW
  /// MAV_DATA_STREAM_RC_CHANNELS
  MAV_DATA_STREAM_RC_CHANNELS = 3,
  /// Enable ATTITUDE_CONTROLLER_OUTPUT, POSITION_CONTROLLER_OUTPUT, NAV_CONTROLLER_OUTPUT.
  /// MAV_DATA_STREAM_RAW_CONTROLLER
  MAV_DATA_STREAM_RAW_CONTROLLER = 4,
  /// Enable LOCAL_POSITION, GLOBAL_POSITION/GLOBAL_POSITION_INT messages.
  /// MAV_DATA_STREAM_POSITION
  MAV_DATA_STREAM_POSITION = 6,
  /// Dependent on the autopilot
  /// MAV_DATA_STREAM_EXTRA1
  MAV_DATA_STREAM_EXTRA1 = 10,
  /// Dependent on the autopilot
  /// MAV_DATA_STREAM_EXTRA2
  MAV_DATA_STREAM_EXTRA2 = 11,
  /// Dependent on the autopilot
  /// MAV_DATA_STREAM_EXTRA3
  MAV_DATA_STREAM_EXTRA3 = 12
}

impl MavDataStream {
  pub fn from_value(value: i32) -> Self {
    match value {
      0 => Self::MAV_DATA_STREAM_ALL,
      1 => Self::MAV_DATA_STREAM_RAW_SENSORS,
      2 => Self::MAV_DATA_STREAM_EXTENDED_STATUS,
      3 => Self::MAV_DATA_STREAM_RC_CHANNELS,
      4 => Self::MAV_DATA_STREAM_RAW_CONTROLLER,
      6 => Self::MAV_DATA_STREAM_POSITION,
      10 => Self::MAV_DATA_STREAM_EXTRA1,
      11 => Self::MAV_DATA_STREAM_EXTRA2,
      12 => Self::MAV_DATA_STREAM_EXTRA3,
      _ => Self::MAV_DATA_STREAM_ALL,
    }
  }
}

/// The ROI (region of interest) for the vehicle. This can be
/// be used by the vehicle for camera/vehicle attitude alignment (see
/// MAV_CMD_NAV_ROI).
/// MAV_ROI
#[repr(i32)]
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum MavRoi {
  /// No region of interest.
  /// MAV_ROI_NONE
  MAV_ROI_NONE = 0,
  /// Point toward next waypoint, with optional pitch/roll/yaw offset.
  /// MAV_ROI_WPNEXT
  MAV_ROI_WPNEXT = 1,
  /// Point toward given waypoint.
  /// MAV_ROI_WPINDEX
  MAV_ROI_WPINDEX = 2,
  /// Point toward fixed location.
  /// MAV_ROI_LOCATION
  MAV_ROI_LOCATION = 3,
  /// Point toward of given id.
  /// MAV_ROI_TARGET
  MAV_ROI_TARGET = 4
}

impl MavRoi {
  pub fn from_value(value: i32) -> Self {
    match value {
      0 => Self::MAV_ROI_NONE,
      1 => Self::MAV_ROI_WPNEXT,
      2 => Self::MAV_ROI_WPINDEX,
      3 => Self::MAV_ROI_LOCATION,
      4 => Self::MAV_ROI_TARGET,
      _ => Self::MAV_ROI_NONE,
    }
  }
}

/// Specifies the datatype of a MAVLink parameter.
/// MAV_PARAM_TYPE
#[repr(i32)]
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum MavParamType {
  /// 8-bit unsigned integer
  /// MAV_PARAM_TYPE_UINT8
  MAV_PARAM_TYPE_UINT8 = 1,
  /// 8-bit signed integer
  /// MAV_PARAM_TYPE_INT8
  MAV_PARAM_TYPE_INT8 = 2,
  /// 16-bit unsigned integer
  /// MAV_PARAM_TYPE_UINT16
  MAV_PARAM_TYPE_UINT16 = 3,
  /// 16-bit signed integer
  /// MAV_PARAM_TYPE_INT16
  MAV_PARAM_TYPE_INT16 = 4,
  /// 32-bit unsigned integer
  /// MAV_PARAM_TYPE_UINT32
  MAV_PARAM_TYPE_UINT32 = 5,
  /// 32-bit signed integer
  /// MAV_PARAM_TYPE_INT32
  MAV_PARAM_TYPE_INT32 = 6,
  /// 64-bit unsigned integer
  /// MAV_PARAM_TYPE_UINT64
  MAV_PARAM_TYPE_UINT64 = 7,
  /// 64-bit signed integer
  /// MAV_PARAM_TYPE_INT64
  MAV_PARAM_TYPE_INT64 = 8,
  /// 32-bit floating-point
  /// MAV_PARAM_TYPE_REAL32
  MAV_PARAM_TYPE_REAL32 = 9,
  /// 64-bit floating-point
  /// MAV_PARAM_TYPE_REAL64
  MAV_PARAM_TYPE_REAL64 = 10
}

impl MavParamType {
  pub fn from_value(value: i32) -> Self {
    match value {
      1 => Self::MAV_PARAM_TYPE_UINT8,
      2 => Self::MAV_PARAM_TYPE_INT8,
      3 => Self::MAV_PARAM_TYPE_UINT16,
      4 => Self::MAV_PARAM_TYPE_INT16,
      5 => Self::MAV_PARAM_TYPE_UINT32,
      6 => Self::MAV_PARAM_TYPE_INT32,
      7 => Self::MAV_PARAM_TYPE_UINT64,
      8 => Self::MAV_PARAM_TYPE_INT64,
      9 => Self::MAV_PARAM_TYPE_REAL32,
      10 => Self::MAV_PARAM_TYPE_REAL64,
      _ => Self::MAV_PARAM_TYPE_UINT8,
    }
  }
}

