/// Result from a MAVLink command (MAV_CMD)
/// MAV_RESULT
#[repr(i32)]
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum MavResult {
  /// Command is valid (is supported and has valid parameters), and was executed.
  /// MAV_RESULT_ACCEPTED
  MAV_RESULT_ACCEPTED = 0,
  /// Command is valid, but cannot be executed at this time. This is used to indicate a problem that should be fixed just by waiting (e.g. a state machine is busy, can't arm because have not got GPS lock, etc.). Retrying later should work.
  /// MAV_RESULT_TEMPORARILY_REJECTED
  MAV_RESULT_TEMPORARILY_REJECTED = 1,
  /// Command is invalid (is supported but has invalid parameters). Retrying same command and parameters will not work.
  /// MAV_RESULT_DENIED
  MAV_RESULT_DENIED = 2,
  /// Command is not supported (unknown).
  /// MAV_RESULT_UNSUPPORTED
  MAV_RESULT_UNSUPPORTED = 3,
  /// Command is valid, but execution has failed. This is used to indicate any non-temporary or unexpected problem, i.e. any problem that must be fixed before the command can succeed/be retried. For example, attempting to write a file when out of memory, attempting to arm when sensors are not calibrated, etc.
  /// MAV_RESULT_FAILED
  MAV_RESULT_FAILED = 4,
  /// Command is valid and is being executed. This will be followed by further progress updates, i.e. the component may send further COMMAND_ACK messages with result MAV_RESULT_IN_PROGRESS (at a rate decided by the implementation), and must terminate by sending a COMMAND_ACK message with final result of the operation. The COMMAND_ACK.progress field can be used to indicate the progress of the operation. There is no need for the sender to retry the command, but if done during execution, the component will return MAV_RESULT_IN_PROGRESS with an updated progress.
  /// MAV_RESULT_IN_PROGRESS
  MAV_RESULT_IN_PROGRESS = 5,
  /// Command is only accepted when sent as a COMMAND_LONG.
  /// MAV_RESULT_COMMAND_LONG_ONLY
  MAV_RESULT_COMMAND_LONG_ONLY = 7,
  /// Command is only accepted when sent as a COMMAND_INT.
  /// MAV_RESULT_COMMAND_INT_ONLY
  MAV_RESULT_COMMAND_INT_ONLY = 8
}

impl MavResult {
  pub fn from_value(value: i32) -> Self {
    match value {
      0 => Self::MAV_RESULT_ACCEPTED,
      1 => Self::MAV_RESULT_TEMPORARILY_REJECTED,
      2 => Self::MAV_RESULT_DENIED,
      3 => Self::MAV_RESULT_UNSUPPORTED,
      4 => Self::MAV_RESULT_FAILED,
      5 => Self::MAV_RESULT_IN_PROGRESS,
      7 => Self::MAV_RESULT_COMMAND_LONG_ONLY,
      8 => Self::MAV_RESULT_COMMAND_INT_ONLY,
      _ => Self::MAV_RESULT_ACCEPTED,
    }
  }
}

/// Result of mission operation (in a MISSION_ACK message).
/// MAV_MISSION_RESULT
#[repr(i32)]
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum MavMissionResult {
  /// mission accepted OK
  /// MAV_MISSION_ACCEPTED
  MAV_MISSION_ACCEPTED = 0,
  /// Generic error / not accepting mission commands at all right now.
  /// MAV_MISSION_ERROR
  MAV_MISSION_ERROR = 1,
  /// Coordinate frame is not supported.
  /// MAV_MISSION_UNSUPPORTED_FRAME
  MAV_MISSION_UNSUPPORTED_FRAME = 2,
  /// Command is not supported.
  /// MAV_MISSION_UNSUPPORTED
  MAV_MISSION_UNSUPPORTED = 3,
  /// Mission items exceed storage space.
  /// MAV_MISSION_NO_SPACE
  MAV_MISSION_NO_SPACE = 4,
  /// One of the parameters has an invalid value.
  /// MAV_MISSION_INVALID
  MAV_MISSION_INVALID = 5,
  /// param1 has an invalid value.
  /// MAV_MISSION_INVALID_PARAM1
  MAV_MISSION_INVALID_PARAM1 = 6,
  /// param2 has an invalid value.
  /// MAV_MISSION_INVALID_PARAM2
  MAV_MISSION_INVALID_PARAM2 = 7,
  /// param3 has an invalid value.
  /// MAV_MISSION_INVALID_PARAM3
  MAV_MISSION_INVALID_PARAM3 = 8,
  /// param4 has an invalid value.
  /// MAV_MISSION_INVALID_PARAM4
  MAV_MISSION_INVALID_PARAM4 = 9,
  /// x / param5 has an invalid value.
  /// MAV_MISSION_INVALID_PARAM5_X
  MAV_MISSION_INVALID_PARAM5_X = 10,
  /// y / param6 has an invalid value.
  /// MAV_MISSION_INVALID_PARAM6_Y
  MAV_MISSION_INVALID_PARAM6_Y = 11,
  /// z / param7 has an invalid value.
  /// MAV_MISSION_INVALID_PARAM7
  MAV_MISSION_INVALID_PARAM7 = 12,
  /// Mission item received out of sequence
  /// MAV_MISSION_INVALID_SEQUENCE
  MAV_MISSION_INVALID_SEQUENCE = 13,
  /// Not accepting any mission commands from this communication partner.
  /// MAV_MISSION_DENIED
  MAV_MISSION_DENIED = 14,
  /// Current mission operation cancelled (e.g. mission upload, mission download).
  /// MAV_MISSION_OPERATION_CANCELLED
  MAV_MISSION_OPERATION_CANCELLED = 15
}

impl MavMissionResult {
  pub fn from_value(value: i32) -> Self {
    match value {
      0 => Self::MAV_MISSION_ACCEPTED,
      1 => Self::MAV_MISSION_ERROR,
      2 => Self::MAV_MISSION_UNSUPPORTED_FRAME,
      3 => Self::MAV_MISSION_UNSUPPORTED,
      4 => Self::MAV_MISSION_NO_SPACE,
      5 => Self::MAV_MISSION_INVALID,
      6 => Self::MAV_MISSION_INVALID_PARAM1,
      7 => Self::MAV_MISSION_INVALID_PARAM2,
      8 => Self::MAV_MISSION_INVALID_PARAM3,
      9 => Self::MAV_MISSION_INVALID_PARAM4,
      10 => Self::MAV_MISSION_INVALID_PARAM5_X,
      11 => Self::MAV_MISSION_INVALID_PARAM6_Y,
      12 => Self::MAV_MISSION_INVALID_PARAM7,
      13 => Self::MAV_MISSION_INVALID_SEQUENCE,
      14 => Self::MAV_MISSION_DENIED,
      15 => Self::MAV_MISSION_OPERATION_CANCELLED,
      _ => Self::MAV_MISSION_ACCEPTED,
    }
  }
}

/// Indicates the severity level, generally used for status messages to indicate their relative urgency. Based on RFC-5424 using expanded definitions at: http://www.kiwisyslog.com/kb/info:-syslog-message-levels/.
/// MAV_SEVERITY
#[repr(i32)]
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum MavSeverity {
  /// System is unusable. This is a "panic" condition.
  /// MAV_SEVERITY_EMERGENCY
  MAV_SEVERITY_EMERGENCY = 0,
  /// Action should be taken immediately. Indicates error in non-critical systems.
  /// MAV_SEVERITY_ALERT
  MAV_SEVERITY_ALERT = 1,
  /// Action must be taken immediately. Indicates failure in a primary system.
  /// MAV_SEVERITY_CRITICAL
  MAV_SEVERITY_CRITICAL = 2,
  /// Indicates an error in secondary/redundant systems.
  /// MAV_SEVERITY_ERROR
  MAV_SEVERITY_ERROR = 3,
  /// Indicates about a possible future error if this is not resolved within a given timeframe. Example would be a low battery warning.
  /// MAV_SEVERITY_WARNING
  MAV_SEVERITY_WARNING = 4,
  /// An unusual event has occurred, though not an error condition. This should be investigated for the root cause.
  /// MAV_SEVERITY_NOTICE
  MAV_SEVERITY_NOTICE = 5,
  /// Normal operational messages. Useful for logging. No action is required for these messages.
  /// MAV_SEVERITY_INFO
  MAV_SEVERITY_INFO = 6,
  /// Useful non-operational messages that can assist in debugging. These should not occur during normal operation.
  /// MAV_SEVERITY_DEBUG
  MAV_SEVERITY_DEBUG = 7
}

impl MavSeverity {
  pub fn from_value(value: i32) -> Self {
    match value {
      0 => Self::MAV_SEVERITY_EMERGENCY,
      1 => Self::MAV_SEVERITY_ALERT,
      2 => Self::MAV_SEVERITY_CRITICAL,
      3 => Self::MAV_SEVERITY_ERROR,
      4 => Self::MAV_SEVERITY_WARNING,
      5 => Self::MAV_SEVERITY_NOTICE,
      6 => Self::MAV_SEVERITY_INFO,
      7 => Self::MAV_SEVERITY_DEBUG,
      _ => Self::MAV_SEVERITY_EMERGENCY,
    }
  }
}

/// Power supply status flags (bitmask)
/// MAV_POWER_STATUS
#[repr(i32)]
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum MavPowerStatus {
  /// main brick power supply valid
  /// MAV_POWER_STATUS_BRICK_VALID
  MAV_POWER_STATUS_BRICK_VALID = 1,
  /// main servo power supply valid for FMU
  /// MAV_POWER_STATUS_SERVO_VALID
  MAV_POWER_STATUS_SERVO_VALID = 2,
  /// USB power is connected
  /// MAV_POWER_STATUS_USB_CONNECTED
  MAV_POWER_STATUS_USB_CONNECTED = 4,
  /// peripheral supply is in over-current state
  /// MAV_POWER_STATUS_PERIPH_OVERCURRENT
  MAV_POWER_STATUS_PERIPH_OVERCURRENT = 8,
  /// hi-power peripheral supply is in over-current state
  /// MAV_POWER_STATUS_PERIPH_HIPOWER_OVERCURRENT
  MAV_POWER_STATUS_PERIPH_HIPOWER_OVERCURRENT = 16,
  /// Power status has changed since boot
  /// MAV_POWER_STATUS_CHANGED
  MAV_POWER_STATUS_CHANGED = 32
}

impl MavPowerStatus {
  pub fn from_value(value: i32) -> Self {
    let variants = [
      Self::MAV_POWER_STATUS_BRICK_VALID,
      Self::MAV_POWER_STATUS_SERVO_VALID,
      Self::MAV_POWER_STATUS_USB_CONNECTED,
      Self::MAV_POWER_STATUS_PERIPH_OVERCURRENT,
      Self::MAV_POWER_STATUS_PERIPH_HIPOWER_OVERCURRENT,
      Self::MAV_POWER_STATUS_CHANGED,
    ];
    for variant in variants {
      if (variant as i32) == value {
        return variant;
      }
    }
    let mut sorted: Vec<Self> = variants.into_iter().filter(|v| *v as i32 > 0).collect();
    sorted.sort_by(|a, b| (*b as i32).cmp(&(*a as i32)));
    for variant in sorted {
      if (value & (variant as i32)) != 0 {
        return variant;
      }
    }
    return Self::MAV_POWER_STATUS_BRICK_VALID;
  }
}

