/// Bitmask of (optional) autopilot capabilities (64 bit). If a bit is set, the autopilot supports this capability.
/// MAV_PROTOCOL_CAPABILITY
#[repr(i32)]
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum MavProtocolCapability {
  /// Autopilot supports MISSION float message type.
  /// MAV_PROTOCOL_CAPABILITY_MISSION_FLOAT
  MAV_PROTOCOL_CAPABILITY_MISSION_FLOAT = 1,
  /// Autopilot supports the new param float message type.
  /// MAV_PROTOCOL_CAPABILITY_PARAM_FLOAT
  MAV_PROTOCOL_CAPABILITY_PARAM_FLOAT = 2,
  /// Autopilot supports MISSION_ITEM_INT scaled integer message type.
  /// MAV_PROTOCOL_CAPABILITY_MISSION_INT
  MAV_PROTOCOL_CAPABILITY_MISSION_INT = 4,
  /// Autopilot supports COMMAND_INT scaled integer message type.
  /// MAV_PROTOCOL_CAPABILITY_COMMAND_INT
  MAV_PROTOCOL_CAPABILITY_COMMAND_INT = 8,
  /// Autopilot supports the new param union message type.
  /// MAV_PROTOCOL_CAPABILITY_PARAM_UNION
  MAV_PROTOCOL_CAPABILITY_PARAM_UNION = 16,
  /// Autopilot supports the File Transfer Protocol v1: https://mavlink.io/en/services/ftp.html.
  /// MAV_PROTOCOL_CAPABILITY_FTP
  MAV_PROTOCOL_CAPABILITY_FTP = 32,
  /// Autopilot supports commanding attitude offboard.
  /// MAV_PROTOCOL_CAPABILITY_SET_ATTITUDE_TARGET
  MAV_PROTOCOL_CAPABILITY_SET_ATTITUDE_TARGET = 64,
  /// Autopilot supports commanding position and velocity targets in local NED frame.
  /// MAV_PROTOCOL_CAPABILITY_SET_POSITION_TARGET_LOCAL_NED
  MAV_PROTOCOL_CAPABILITY_SET_POSITION_TARGET_LOCAL_NED = 128,
  /// Autopilot supports commanding position and velocity targets in global scaled integers.
  /// MAV_PROTOCOL_CAPABILITY_SET_POSITION_TARGET_GLOBAL_INT
  MAV_PROTOCOL_CAPABILITY_SET_POSITION_TARGET_GLOBAL_INT = 256,
  /// Autopilot supports terrain protocol / data handling.
  /// MAV_PROTOCOL_CAPABILITY_TERRAIN
  MAV_PROTOCOL_CAPABILITY_TERRAIN = 512,
  /// Autopilot supports direct actuator control.
  /// MAV_PROTOCOL_CAPABILITY_SET_ACTUATOR_TARGET
  MAV_PROTOCOL_CAPABILITY_SET_ACTUATOR_TARGET = 1024,
  /// Autopilot supports the MAV_CMD_DO_FLIGHTTERMINATION command (flight termination).
  /// MAV_PROTOCOL_CAPABILITY_FLIGHT_TERMINATION
  MAV_PROTOCOL_CAPABILITY_FLIGHT_TERMINATION = 2048,
  /// Autopilot supports onboard compass calibration.
  /// MAV_PROTOCOL_CAPABILITY_COMPASS_CALIBRATION
  MAV_PROTOCOL_CAPABILITY_COMPASS_CALIBRATION = 4096,
  /// Autopilot supports MAVLink version 2.
  /// MAV_PROTOCOL_CAPABILITY_MAVLINK2
  MAV_PROTOCOL_CAPABILITY_MAVLINK2 = 8192,
  /// Autopilot supports mission fence protocol.
  /// MAV_PROTOCOL_CAPABILITY_MISSION_FENCE
  MAV_PROTOCOL_CAPABILITY_MISSION_FENCE = 16384,
  /// Autopilot supports mission rally point protocol.
  /// MAV_PROTOCOL_CAPABILITY_MISSION_RALLY
  MAV_PROTOCOL_CAPABILITY_MISSION_RALLY = 32768,
  /// Autopilot supports the flight information protocol.
  /// MAV_PROTOCOL_CAPABILITY_FLIGHT_INFORMATION
  MAV_PROTOCOL_CAPABILITY_FLIGHT_INFORMATION = 65536
}

impl MavProtocolCapability {
  pub fn from_value(value: i32) -> Self {
    let variants = [
      Self::MAV_PROTOCOL_CAPABILITY_MISSION_FLOAT,
      Self::MAV_PROTOCOL_CAPABILITY_PARAM_FLOAT,
      Self::MAV_PROTOCOL_CAPABILITY_MISSION_INT,
      Self::MAV_PROTOCOL_CAPABILITY_COMMAND_INT,
      Self::MAV_PROTOCOL_CAPABILITY_PARAM_UNION,
      Self::MAV_PROTOCOL_CAPABILITY_FTP,
      Self::MAV_PROTOCOL_CAPABILITY_SET_ATTITUDE_TARGET,
      Self::MAV_PROTOCOL_CAPABILITY_SET_POSITION_TARGET_LOCAL_NED,
      Self::MAV_PROTOCOL_CAPABILITY_SET_POSITION_TARGET_GLOBAL_INT,
      Self::MAV_PROTOCOL_CAPABILITY_TERRAIN,
      Self::MAV_PROTOCOL_CAPABILITY_SET_ACTUATOR_TARGET,
      Self::MAV_PROTOCOL_CAPABILITY_FLIGHT_TERMINATION,
      Self::MAV_PROTOCOL_CAPABILITY_COMPASS_CALIBRATION,
      Self::MAV_PROTOCOL_CAPABILITY_MAVLINK2,
      Self::MAV_PROTOCOL_CAPABILITY_MISSION_FENCE,
      Self::MAV_PROTOCOL_CAPABILITY_MISSION_RALLY,
      Self::MAV_PROTOCOL_CAPABILITY_FLIGHT_INFORMATION,
    ];
    for variant in variants {
      if (variant as i32) == value {
        return variant;
      }
    }
    let mut sorted: Vec<Self> = variants.into_iter().filter(|v| *v as i32 > 0).collect();
    sorted.sort_by(|a, b| (*b as i32).cmp(&(*a as i32)));
    for variant in sorted {
      if (value & (variant as i32)) != 0 {
        return variant;
      }
    }
    return Self::MAV_PROTOCOL_CAPABILITY_MISSION_FLOAT;
  }
}

/// Type of mission items being requested/sent in mission protocol.
/// MAV_MISSION_TYPE
#[repr(i32)]
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum MavMissionType {
  /// Items are mission commands for main mission.
  /// MAV_MISSION_TYPE_MISSION
  MAV_MISSION_TYPE_MISSION = 0,
  /// Specifies GeoFence area(s). Items are MAV_CMD_NAV_FENCE_ GeoFence items.
  /// MAV_MISSION_TYPE_FENCE
  MAV_MISSION_TYPE_FENCE = 1,
  /// Specifies the rally points for the vehicle. Rally points are alternative RTL points. Items are MAV_CMD_NAV_RALLY_POINT rally point items.
  /// MAV_MISSION_TYPE_RALLY
  MAV_MISSION_TYPE_RALLY = 2,
  /// Only used in MISSION_CLEAR_ALL to clear all mission types.
  /// MAV_MISSION_TYPE_ALL
  MAV_MISSION_TYPE_ALL = 255
}

impl MavMissionType {
  pub fn from_value(value: i32) -> Self {
    match value {
      0 => Self::MAV_MISSION_TYPE_MISSION,
      1 => Self::MAV_MISSION_TYPE_FENCE,
      2 => Self::MAV_MISSION_TYPE_RALLY,
      255 => Self::MAV_MISSION_TYPE_ALL,
      _ => Self::MAV_MISSION_TYPE_MISSION,
    }
  }
}

