/// Possible actions an aircraft can take to avoid a collision.
/// MAV_COLLISION_ACTION
#[repr(i32)]
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum MavCollisionAction {
  /// Ignore any potential collisions
  /// MAV_COLLISION_ACTION_NONE
  MAV_COLLISION_ACTION_NONE = 0,
  /// Report potential collision
  /// MAV_COLLISION_ACTION_REPORT
  MAV_COLLISION_ACTION_REPORT = 1,
  /// Ascend or Descend to avoid threat
  /// MAV_COLLISION_ACTION_ASCEND_OR_DESCEND
  MAV_COLLISION_ACTION_ASCEND_OR_DESCEND = 2,
  /// Move horizontally to avoid threat
  /// MAV_COLLISION_ACTION_MOVE_HORIZONTALLY
  MAV_COLLISION_ACTION_MOVE_HORIZONTALLY = 3,
  /// Aircraft to move perpendicular to the collision's velocity vector
  /// MAV_COLLISION_ACTION_MOVE_PERPENDICULAR
  MAV_COLLISION_ACTION_MOVE_PERPENDICULAR = 4,
  /// Aircraft to fly directly back to its launch point
  /// MAV_COLLISION_ACTION_RTL
  MAV_COLLISION_ACTION_RTL = 5,
  /// Aircraft to stop in place
  /// MAV_COLLISION_ACTION_HOVER
  MAV_COLLISION_ACTION_HOVER = 6
}

impl MavCollisionAction {
  pub fn from_value(value: i32) -> Self {
    match value {
      0 => Self::MAV_COLLISION_ACTION_NONE,
      1 => Self::MAV_COLLISION_ACTION_REPORT,
      2 => Self::MAV_COLLISION_ACTION_ASCEND_OR_DESCEND,
      3 => Self::MAV_COLLISION_ACTION_MOVE_HORIZONTALLY,
      4 => Self::MAV_COLLISION_ACTION_MOVE_PERPENDICULAR,
      5 => Self::MAV_COLLISION_ACTION_RTL,
      6 => Self::MAV_COLLISION_ACTION_HOVER,
      _ => Self::MAV_COLLISION_ACTION_NONE,
    }
  }
}

