/// Camera capability flags (Bitmap)
/// CAMERA_CAP_FLAGS
#[repr(i32)]
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum CameraCapFlags {
  /// Camera is able to record video
  /// CAMERA_CAP_FLAGS_CAPTURE_VIDEO
  CAMERA_CAP_FLAGS_CAPTURE_VIDEO = 1,
  /// Camera is able to capture images
  /// CAMERA_CAP_FLAGS_CAPTURE_IMAGE
  CAMERA_CAP_FLAGS_CAPTURE_IMAGE = 2,
  /// Camera has separate Video and Image/Photo modes (MAV_CMD_SET_CAMERA_MODE)
  /// CAMERA_CAP_FLAGS_HAS_MODES
  CAMERA_CAP_FLAGS_HAS_MODES = 4,
  /// Camera can capture images while in video mode
  /// CAMERA_CAP_FLAGS_CAN_CAPTURE_IMAGE_IN_VIDEO_MODE
  CAMERA_CAP_FLAGS_CAN_CAPTURE_IMAGE_IN_VIDEO_MODE = 8,
  /// Camera can capture videos while in Photo/Image mode
  /// CAMERA_CAP_FLAGS_CAN_CAPTURE_VIDEO_IN_IMAGE_MODE
  CAMERA_CAP_FLAGS_CAN_CAPTURE_VIDEO_IN_IMAGE_MODE = 16,
  /// Camera has image survey mode (MAV_CMD_SET_CAMERA_MODE)
  /// CAMERA_CAP_FLAGS_HAS_IMAGE_SURVEY_MODE
  CAMERA_CAP_FLAGS_HAS_IMAGE_SURVEY_MODE = 32,
  /// Camera has basic zoom control (MAV_CMD_SET_CAMERA_ZOOM)
  /// CAMERA_CAP_FLAGS_HAS_BASIC_ZOOM
  CAMERA_CAP_FLAGS_HAS_BASIC_ZOOM = 64,
  /// Camera has basic focus control (MAV_CMD_SET_CAMERA_FOCUS)
  /// CAMERA_CAP_FLAGS_HAS_BASIC_FOCUS
  CAMERA_CAP_FLAGS_HAS_BASIC_FOCUS = 128,
  /// Camera has video streaming capabilities (request VIDEO_STREAM_INFORMATION with MAV_CMD_REQUEST_MESSAGE for video streaming info)
  /// CAMERA_CAP_FLAGS_HAS_VIDEO_STREAM
  CAMERA_CAP_FLAGS_HAS_VIDEO_STREAM = 256,
  /// Camera supports tracking of a point on the camera view.
  /// CAMERA_CAP_FLAGS_HAS_TRACKING_POINT
  CAMERA_CAP_FLAGS_HAS_TRACKING_POINT = 512,
  /// Camera supports tracking of a selection rectangle on the camera view.
  /// CAMERA_CAP_FLAGS_HAS_TRACKING_RECTANGLE
  CAMERA_CAP_FLAGS_HAS_TRACKING_RECTANGLE = 1024,
  /// Camera supports tracking geo status (CAMERA_TRACKING_GEO_STATUS).
  /// CAMERA_CAP_FLAGS_HAS_TRACKING_GEO_STATUS
  CAMERA_CAP_FLAGS_HAS_TRACKING_GEO_STATUS = 2048
}

impl CameraCapFlags {
  pub fn from_value(value: i32) -> Self {
    let variants = [
      Self::CAMERA_CAP_FLAGS_CAPTURE_VIDEO,
      Self::CAMERA_CAP_FLAGS_CAPTURE_IMAGE,
      Self::CAMERA_CAP_FLAGS_HAS_MODES,
      Self::CAMERA_CAP_FLAGS_CAN_CAPTURE_IMAGE_IN_VIDEO_MODE,
      Self::CAMERA_CAP_FLAGS_CAN_CAPTURE_VIDEO_IN_IMAGE_MODE,
      Self::CAMERA_CAP_FLAGS_HAS_IMAGE_SURVEY_MODE,
      Self::CAMERA_CAP_FLAGS_HAS_BASIC_ZOOM,
      Self::CAMERA_CAP_FLAGS_HAS_BASIC_FOCUS,
      Self::CAMERA_CAP_FLAGS_HAS_VIDEO_STREAM,
      Self::CAMERA_CAP_FLAGS_HAS_TRACKING_POINT,
      Self::CAMERA_CAP_FLAGS_HAS_TRACKING_RECTANGLE,
      Self::CAMERA_CAP_FLAGS_HAS_TRACKING_GEO_STATUS,
    ];
    for variant in variants {
      if (variant as i32) == value {
        return variant;
      }
    }
    let mut sorted: Vec<Self> = variants.into_iter().filter(|v| *v as i32 > 0).collect();
    sorted.sort_by(|a, b| (*b as i32).cmp(&(*a as i32)));
    for variant in sorted {
      if (value & (variant as i32)) != 0 {
        return variant;
      }
    }
    return Self::CAMERA_CAP_FLAGS_CAPTURE_VIDEO;
  }
}

