/// These flags are used in the AIS_VESSEL.fields bitmask to indicate validity of data in the other message fields. When set, the data is valid.
/// AIS_FLAGS
#[repr(i32)]
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum AisFlags {
  /// 1 = Position accuracy less than 10m, 0 = position accuracy greater than 10m.
  /// AIS_FLAGS_POSITION_ACCURACY
  AIS_FLAGS_POSITION_ACCURACY = 1,
  /// AIS_FLAGS_VALID_COG
  AIS_FLAGS_VALID_COG = 2,
  /// AIS_FLAGS_VALID_VELOCITY
  AIS_FLAGS_VALID_VELOCITY = 4,
  /// 1 = Velocity over 52.5765m/s (102.2 knots)
  /// AIS_FLAGS_HIGH_VELOCITY
  AIS_FLAGS_HIGH_VELOCITY = 8,
  /// AIS_FLAGS_VALID_TURN_RATE
  AIS_FLAGS_VALID_TURN_RATE = 16,
  /// Only the sign of the returned turn rate value is valid, either greater than 5deg/30s or less than -5deg/30s
  /// AIS_FLAGS_TURN_RATE_SIGN_ONLY
  AIS_FLAGS_TURN_RATE_SIGN_ONLY = 32,
  /// AIS_FLAGS_VALID_DIMENSIONS
  AIS_FLAGS_VALID_DIMENSIONS = 64,
  /// Distance to bow is larger than 511m
  /// AIS_FLAGS_LARGE_BOW_DIMENSION
  AIS_FLAGS_LARGE_BOW_DIMENSION = 128,
  /// Distance to stern is larger than 511m
  /// AIS_FLAGS_LARGE_STERN_DIMENSION
  AIS_FLAGS_LARGE_STERN_DIMENSION = 256,
  /// Distance to port side is larger than 63m
  /// AIS_FLAGS_LARGE_PORT_DIMENSION
  AIS_FLAGS_LARGE_PORT_DIMENSION = 512,
  /// Distance to starboard side is larger than 63m
  /// AIS_FLAGS_LARGE_STARBOARD_DIMENSION
  AIS_FLAGS_LARGE_STARBOARD_DIMENSION = 1024,
  /// AIS_FLAGS_VALID_CALLSIGN
  AIS_FLAGS_VALID_CALLSIGN = 2048,
  /// AIS_FLAGS_VALID_NAME
  AIS_FLAGS_VALID_NAME = 4096
}

impl AisFlags {
  pub fn from_value(value: i32) -> Self {
    let variants = [
      Self::AIS_FLAGS_POSITION_ACCURACY,
      Self::AIS_FLAGS_VALID_COG,
      Self::AIS_FLAGS_VALID_VELOCITY,
      Self::AIS_FLAGS_HIGH_VELOCITY,
      Self::AIS_FLAGS_VALID_TURN_RATE,
      Self::AIS_FLAGS_TURN_RATE_SIGN_ONLY,
      Self::AIS_FLAGS_VALID_DIMENSIONS,
      Self::AIS_FLAGS_LARGE_BOW_DIMENSION,
      Self::AIS_FLAGS_LARGE_STERN_DIMENSION,
      Self::AIS_FLAGS_LARGE_PORT_DIMENSION,
      Self::AIS_FLAGS_LARGE_STARBOARD_DIMENSION,
      Self::AIS_FLAGS_VALID_CALLSIGN,
      Self::AIS_FLAGS_VALID_NAME,
    ];
    for variant in variants {
      if (variant as i32) == value {
        return variant;
      }
    }
    let mut sorted: Vec<Self> = variants.into_iter().filter(|v| *v as i32 > 0).collect();
    sorted.sort_by(|a, b| (*b as i32).cmp(&(*a as i32)));
    for variant in sorted {
      if (value & (variant as i32)) != 0 {
        return variant;
      }
    }
    return Self::AIS_FLAGS_POSITION_ACCURACY;
  }
}

/// Winch status flags used in WINCH_STATUS
/// MAV_WINCH_STATUS_FLAG
#[repr(i32)]
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum MavWinchStatusFlag {
  /// Winch is healthy
  /// MAV_WINCH_STATUS_HEALTHY
  MAV_WINCH_STATUS_HEALTHY = 1,
  /// Winch thread is fully retracted
  /// MAV_WINCH_STATUS_FULLY_RETRACTED
  MAV_WINCH_STATUS_FULLY_RETRACTED = 2,
  /// Winch motor is moving
  /// MAV_WINCH_STATUS_MOVING
  MAV_WINCH_STATUS_MOVING = 4,
  /// Winch clutch is engaged allowing motor to move freely
  /// MAV_WINCH_STATUS_CLUTCH_ENGAGED
  MAV_WINCH_STATUS_CLUTCH_ENGAGED = 8
}

impl MavWinchStatusFlag {
  pub fn from_value(value: i32) -> Self {
    let variants = [
      Self::MAV_WINCH_STATUS_HEALTHY,
      Self::MAV_WINCH_STATUS_FULLY_RETRACTED,
      Self::MAV_WINCH_STATUS_MOVING,
      Self::MAV_WINCH_STATUS_CLUTCH_ENGAGED,
    ];
    for variant in variants {
      if (variant as i32) == value {
        return variant;
      }
    }
    let mut sorted: Vec<Self> = variants.into_iter().filter(|v| *v as i32 > 0).collect();
    sorted.sort_by(|a, b| (*b as i32).cmp(&(*a as i32)));
    for variant in sorted {
      if (value & (variant as i32)) != 0 {
        return variant;
      }
    }
    return Self::MAV_WINCH_STATUS_HEALTHY;
  }
}

