/// State flags for ADS-B transponder fault report
/// UAVIONIX_ADSB_OUT_STATUS_FAULT
#[repr(i32)]
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum UavionixAdsbOutStatusFault {
  /// UAVIONIX_ADSB_OUT_STATUS_FAULT_STATUS_MESSAGE_UNAVAIL
  UAVIONIX_ADSB_OUT_STATUS_FAULT_STATUS_MESSAGE_UNAVAIL = 8,
  /// UAVIONIX_ADSB_OUT_STATUS_FAULT_GPS_NO_POS
  UAVIONIX_ADSB_OUT_STATUS_FAULT_GPS_NO_POS = 16,
  /// UAVIONIX_ADSB_OUT_STATUS_FAULT_GPS_UNAVAIL
  UAVIONIX_ADSB_OUT_STATUS_FAULT_GPS_UNAVAIL = 32,
  /// UAVIONIX_ADSB_OUT_STATUS_FAULT_TX_SYSTEM_FAIL
  UAVIONIX_ADSB_OUT_STATUS_FAULT_TX_SYSTEM_FAIL = 64,
  /// UAVIONIX_ADSB_OUT_STATUS_FAULT_MAINT_REQ
  UAVIONIX_ADSB_OUT_STATUS_FAULT_MAINT_REQ = 128
}

impl UavionixAdsbOutStatusFault {
  pub fn from_value(value: i32) -> Self {
    let variants = [
      Self::UAVIONIX_ADSB_OUT_STATUS_FAULT_STATUS_MESSAGE_UNAVAIL,
      Self::UAVIONIX_ADSB_OUT_STATUS_FAULT_GPS_NO_POS,
      Self::UAVIONIX_ADSB_OUT_STATUS_FAULT_GPS_UNAVAIL,
      Self::UAVIONIX_ADSB_OUT_STATUS_FAULT_TX_SYSTEM_FAIL,
      Self::UAVIONIX_ADSB_OUT_STATUS_FAULT_MAINT_REQ,
    ];
    for variant in variants {
      if (variant as i32) == value {
        return variant;
      }
    }
    let mut sorted: Vec<Self> = variants.into_iter().filter(|v| *v as i32 > 0).collect();
    sorted.sort_by(|a, b| (*b as i32).cmp(&(*a as i32)));
    for variant in sorted {
      if (value & (variant as i32)) != 0 {
        return variant;
      }
    }
    return Self::UAVIONIX_ADSB_OUT_STATUS_FAULT_STATUS_MESSAGE_UNAVAIL;
  }
}

