/// Flags in EKF_STATUS message.
/// EKF_STATUS_FLAGS
#[repr(i32)]
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum EkfStatusFlags {
  /// Set if EKF's attitude estimate is good.
  /// EKF_ATTITUDE
  EKF_ATTITUDE = 1,
  /// Set if EKF's horizontal velocity estimate is good.
  /// EKF_VELOCITY_HORIZ
  EKF_VELOCITY_HORIZ = 2,
  /// Set if EKF's vertical velocity estimate is good.
  /// EKF_VELOCITY_VERT
  EKF_VELOCITY_VERT = 4,
  /// Set if EKF's horizontal position (relative) estimate is good.
  /// EKF_POS_HORIZ_REL
  EKF_POS_HORIZ_REL = 8,
  /// Set if EKF's horizontal position (absolute) estimate is good.
  /// EKF_POS_HORIZ_ABS
  EKF_POS_HORIZ_ABS = 16,
  /// Set if EKF's vertical position (absolute) estimate is good.
  /// EKF_POS_VERT_ABS
  EKF_POS_VERT_ABS = 32,
  /// Set if EKF's vertical position (above ground) estimate is good.
  /// EKF_POS_VERT_AGL
  EKF_POS_VERT_AGL = 64,
  /// EKF is in constant position mode and does not know it's absolute or relative position.
  /// EKF_CONST_POS_MODE
  EKF_CONST_POS_MODE = 128,
  /// Set if EKF's predicted horizontal position (relative) estimate is good.
  /// EKF_PRED_POS_HORIZ_REL
  EKF_PRED_POS_HORIZ_REL = 256,
  /// Set if EKF's predicted horizontal position (absolute) estimate is good.
  /// EKF_PRED_POS_HORIZ_ABS
  EKF_PRED_POS_HORIZ_ABS = 512,
  /// Set if EKF has never been healthy.
  /// EKF_UNINITIALIZED
  EKF_UNINITIALIZED = 1024
}

impl EkfStatusFlags {
  pub fn from_value(value: i32) -> Self {
    let variants = [
      Self::EKF_ATTITUDE,
      Self::EKF_VELOCITY_HORIZ,
      Self::EKF_VELOCITY_VERT,
      Self::EKF_POS_HORIZ_REL,
      Self::EKF_POS_HORIZ_ABS,
      Self::EKF_POS_VERT_ABS,
      Self::EKF_POS_VERT_AGL,
      Self::EKF_CONST_POS_MODE,
      Self::EKF_PRED_POS_HORIZ_REL,
      Self::EKF_PRED_POS_HORIZ_ABS,
      Self::EKF_UNINITIALIZED,
    ];
    for variant in variants {
      if (variant as i32) == value {
        return variant;
      }
    }
    let mut sorted: Vec<Self> = variants.into_iter().filter(|v| *v as i32 > 0).collect();
    sorted.sort_by(|a, b| (*b as i32).cmp(&(*a as i32)));
    for variant in sorted {
      if (value & (variant as i32)) != 0 {
        return variant;
      }
    }
    return Self::EKF_ATTITUDE;
  }
}

