/// Handshake message to initiate, control and stop image streaming when using the Image Transmission Protocol: https://mavlink.io/en/services/image_transmission.html.
/// DATA_TRANSMISSION_HANDSHAKE
#[derive(Debug, Clone, PartialEq)]
pub struct DataTransmissionHandshake {

  /// total data size (set on ACK only).
  /// MAVLink type: uint32_t
  /// units: bytes
  /// size
  pub size: u32,

  /// Width of a matrix or image.
  /// MAVLink type: uint16_t
  /// width
  pub width: u16,

  /// Height of a matrix or image.
  /// MAVLink type: uint16_t
  /// height
  pub height: u16,

  /// Number of packets being sent (set on ACK only).
  /// MAVLink type: uint16_t
  /// packets
  pub packets: u16,

  /// Type of requested/acknowledged data.
  /// MAVLink type: uint8_t
  /// enum: [MavlinkDataStreamType]
  /// type
  pub r#type: MavlinkDataStreamType,

  /// Payload size per packet (normally 253 byte, see DATA field size in message ENCAPSULATED_DATA) (set on ACK only).
  /// MAVLink type: uint8_t
  /// units: bytes
  /// payload
  pub payload: u8,

  /// JPEG quality. Values: [1-100].
  /// MAVLink type: uint8_t
  /// units: %
  /// jpg_quality
  pub jpg_quality: u8,
}

impl DataTransmissionHandshake {
  pub const MSG_ID: u32 = 130;
  pub const CRC_EXTRA: u8 = 29;
  pub const MAVLINK_ENCODED_LENGTH: usize = 13;

  pub fn parse(data: &[u8]) -> Self {
    let padded = crate::mavlink_message::pad_payload(data, Self::MAVLINK_ENCODED_LENGTH);
    let size = crate::mavlink_message::get_u32(&padded, 0);
    let width = crate::mavlink_message::get_u16(&padded, 4);
    let height = crate::mavlink_message::get_u16(&padded, 6);
    let packets = crate::mavlink_message::get_u16(&padded, 8);
    let type_parsed_raw = crate::mavlink_message::get_u8(&padded, 10);
    let type_parsed = MavlinkDataStreamType::from_value(type_parsed_raw as i32);
    let payload = crate::mavlink_message::get_u8(&padded, 11);
    let jpg_quality = crate::mavlink_message::get_u8(&padded, 12);

    DataTransmissionHandshake {
      size: size,
      width: width,
      height: height,
      packets: packets,
      r#type: type_parsed,
      payload: payload,
      jpg_quality: jpg_quality
    }
  }
}

impl MavlinkMessage for DataTransmissionHandshake {
  fn mavlink_message_id(&self) -> u32 {
    Self::MSG_ID
  }

  fn mavlink_crc_extra(&self) -> u8 {
    Self::CRC_EXTRA
  }

  fn serialize(&self) -> Vec<u8> {
    let mut data = vec![0u8; Self::MAVLINK_ENCODED_LENGTH];
    crate::mavlink_message::set_u32(&mut data, 0, self.size);
    crate::mavlink_message::set_u16(&mut data, 4, self.width);
    crate::mavlink_message::set_u16(&mut data, 6, self.height);
    crate::mavlink_message::set_u16(&mut data, 8, self.packets);
    crate::mavlink_message::set_u8(&mut data, 10, self.r#type as i32 as u8);
    crate::mavlink_message::set_u8(&mut data, 11, self.payload);
    crate::mavlink_message::set_u8(&mut data, 12, self.jpg_quality);
    data
  }
}

