/// The current system altitude.
/// ALTITUDE
#[derive(Debug, Clone, PartialEq)]
pub struct Altitude {

  /// Timestamp (UNIX Epoch time or time since system boot). The receiving end can infer timestamp format (since 1.1.1970 or since system boot) by checking for the magnitude of the number.
  /// MAVLink type: uint64_t
  /// units: us
  /// time_usec
  pub time_usec: u64,

  /// This altitude measure is initialized on system boot and monotonic (it is never reset, but represents the local altitude change). The only guarantee on this field is that it will never be reset and is consistent within a flight. The recommended value for this field is the uncorrected barometric altitude at boot time. This altitude will also drift and vary between flights.
  /// MAVLink type: float
  /// units: m
  /// altitude_monotonic
  pub altitude_monotonic: f32,

  /// This altitude measure is strictly above mean sea level and might be non-monotonic (it might reset on events like GPS lock or when a new QNH value is set). It should be the altitude to which global altitude waypoints are compared to. Note that it is *not* the GPS altitude, however, most GPS modules already output MSL by default and not the WGS84 altitude.
  /// MAVLink type: float
  /// units: m
  /// altitude_amsl
  pub altitude_amsl: f32,

  /// This is the local altitude in the local coordinate frame. It is not the altitude above home, but in reference to the coordinate origin (0, 0, 0). It is up-positive.
  /// MAVLink type: float
  /// units: m
  /// altitude_local
  pub altitude_local: f32,

  /// This is the altitude above the home position. It resets on each change of the current home position.
  /// MAVLink type: float
  /// units: m
  /// altitude_relative
  pub altitude_relative: f32,

  /// This is the altitude above terrain. It might be fed by a terrain database or an altimeter. Values smaller than -1000 should be interpreted as unknown.
  /// MAVLink type: float
  /// units: m
  /// altitude_terrain
  pub altitude_terrain: f32,

  /// This is not the altitude, but the clear space below the system according to the fused clearance estimate. It generally should max out at the maximum range of e.g. the laser altimeter. It is generally a moving target. A negative value indicates no measurement available.
  /// MAVLink type: float
  /// units: m
  /// bottom_clearance
  pub bottom_clearance: f32,
}

impl Altitude {
  pub const MSG_ID: u32 = 141;
  pub const CRC_EXTRA: u8 = 47;
  pub const MAVLINK_ENCODED_LENGTH: usize = 32;

  pub fn parse(data: &[u8]) -> Self {
    let padded = crate::mavlink_message::pad_payload(data, Self::MAVLINK_ENCODED_LENGTH);
    let time_usec = crate::mavlink_message::get_u64(&padded, 0);
    let altitude_monotonic = crate::mavlink_message::get_f32(&padded, 8);
    let altitude_amsl = crate::mavlink_message::get_f32(&padded, 12);
    let altitude_local = crate::mavlink_message::get_f32(&padded, 16);
    let altitude_relative = crate::mavlink_message::get_f32(&padded, 20);
    let altitude_terrain = crate::mavlink_message::get_f32(&padded, 24);
    let bottom_clearance = crate::mavlink_message::get_f32(&padded, 28);

    Altitude {
      time_usec: time_usec,
      altitude_monotonic: altitude_monotonic,
      altitude_amsl: altitude_amsl,
      altitude_local: altitude_local,
      altitude_relative: altitude_relative,
      altitude_terrain: altitude_terrain,
      bottom_clearance: bottom_clearance
    }
  }
}

