/// RTCM message for injecting into the onboard GPS (used for DGPS)
/// GPS_RTCM_DATA
#[derive(Debug, Clone, PartialEq)]
pub struct GpsRtcmData {

  /// LSB: 1 means message is fragmented, next 2 bits are the fragment ID, the remaining 5 bits are used for the sequence ID. Messages are only to be flushed to the GPS when the entire message has been reconstructed on the autopilot. The fragment ID specifies which order the fragments should be assembled into a buffer, while the sequence ID is used to detect a mismatch between different buffers. The buffer is considered fully reconstructed when either all 4 fragments are present, or all the fragments before the first fragment with a non full payload is received. This management is used to ensure that normal GPS operation doesn't corrupt RTCM data, and to recover from a unreliable transport delivery order.
  /// MAVLink type: uint8_t
  /// flags
  pub flags: u8,

  /// data length
  /// MAVLink type: uint8_t
  /// units: bytes
  /// len
  pub len: u8,

  /// RTCM message (may be fragmented)
  /// MAVLink type: uint8_t[180]
  /// data
  pub data: [u8; 180],
}

impl GpsRtcmData {
  pub const MSG_ID: u32 = 233;
  pub const CRC_EXTRA: u8 = 35;
  pub const MAVLINK_ENCODED_LENGTH: usize = 182;

  pub fn parse(data: &[u8]) -> Self {
    let padded = crate::mavlink_message::pad_payload(data, Self::MAVLINK_ENCODED_LENGTH);
    let flags = crate::mavlink_message::get_u8(&padded, 0);
    let len = crate::mavlink_message::get_u8(&padded, 1);
    let data = crate::mavlink_message::get_u8_array::<180>(&padded, 2);

    GpsRtcmData {
      flags: flags,
      len: len,
      data: data
    }
  }
}

impl MavlinkMessage for GpsRtcmData {
  fn mavlink_message_id(&self) -> u32 {
    Self::MSG_ID
  }

  fn mavlink_crc_extra(&self) -> u8 {
    Self::CRC_EXTRA
  }

  fn serialize(&self) -> Vec<u8> {
    let mut data = vec![0u8; Self::MAVLINK_ENCODED_LENGTH];
    crate::mavlink_message::set_u8(&mut data, 0, self.flags);
    crate::mavlink_message::set_u8(&mut data, 1, self.len);
    crate::mavlink_message::set_u8_array::<180>(&mut data, 2, &self.data);
    data
  }
}

